from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card(credit_card_number, key):
    fernet = Fernet(key)
    encrypted_number = fernet.encrypt(credit_card_number.encode())
    return encrypted_number

def decrypt_credit_card(encrypted_number, key):
    fernet = Fernet(key)
    decrypted_number = fernet.decrypt(encrypted_number).decode()
    return decrypted_number

